import java.util.Map;
import java.util.Objects;
import com.google.common.collect.ImmutableMap;

public final class GroupConfiguration implements Comparable<GroupConfiguration> {

  private final ImmutableMap<String, String> metadata;
  private final String name;
  private final int maxEntities;
  private final int minEntities;
  private final int cooldown;

  private GroupConfiguration(Builder builder) {
    this.metadata = builder.metadata == null
        ? ImmutableMap.of()
        : ImmutableMap.copyOf(builder.metadata);
    this.name = builder.name;
    this.maxEntities = builder.maxEntities;
    this.minEntities = builder.minEntities;
    this.cooldown = builder.cooldown;
  }

  public ImmutableMap<String, String> getMetadata() {
    return metadata;
  }

  public String getName() {
    return name;
  }

  public int getMaxEntities() {
    return maxEntities;
  }

  public int getMinEntities() {
    return minEntities;
  }

  public int getCooldown() {
    return cooldown;
  }

  public Builder toBuilder() {
    return new Builder().from(this);
  }

  @Override
  public int compareTo(GroupConfiguration o) {
    if (o == null) return 1;
    int c = (this.name == null)
        ? (o.name == null ? 0 : -1)
        : this.name.compareTo(o.name);
    if (c != 0) return c;
    c = Integer.compare(this.maxEntities, o.maxEntities);
    if (c != 0) return c;
    c = Integer.compare(this.minEntities, o.minEntities);
    if (c != 0) return c;
    return Integer.compare(this.cooldown, o.cooldown);
  }

  @Override
  public boolean equals(Object obj) {
    if (this == obj) return true;
    if (!(obj instanceof GroupConfiguration)) return false;
    GroupConfiguration other = (GroupConfiguration) obj;
    return Objects.equals(this.metadata, other.metadata)
        && Objects.equals(this.name, other.name)
        && this.maxEntities == other.maxEntities
        && this.minEntities == other.minEntities
        && this.cooldown == other.cooldown;
  }

  @Override
  public int hashCode() {
    return Objects.hash(metadata, name, maxEntities, minEntities, cooldown);
  }

  @Override
  public String toString() {
    return "GroupConfiguration{" +
        "metadata=" + metadata +
        ", name='" + name + '\'' +
        ", maxEntities=" + maxEntities +
        ", minEntities=" + minEntities +
        ", cooldown=" + cooldown +
        '}';
  }

  public static Builder builder() {
    return new Builder();
  }

  public static final class Builder {
    private Map<String, String> metadata;
    private String name;
    private int maxEntities;
    private int minEntities;
    private int cooldown;

    private Builder() {}

    public Builder metadata(Map<String, String> metadata) {
      this.metadata = metadata;
      return this;
    }

    public Builder name(String name) {
      this.name = name;
      return this;
    }

    public Builder maxEntities(int maxEntities) {
      this.maxEntities = maxEntities;
      return this;
    }

    public Builder minEntities(int minEntities) {
      this.minEntities = minEntities;
      return this;
    }

    public Builder cooldown(int cooldown) {
      this.cooldown = cooldown;
      return this;
    }

    public GroupConfiguration build() {
      return new GroupConfiguration(this);
    }

    public Builder from(GroupConfiguration config) {
      this.metadata = config.metadata;
      this.name = config.name;
      this.maxEntities = config.maxEntities;
      this.minEntities = config.minEntities;
      this.cooldown = config.cooldown;
      return this;
    }
  }

  // Optional convenience derived from the description
  public GroupConfiguration(String name, int maxEntities, int minEntities, int cooldown) {
    this.metadata = ImmutableMap.of();
    this.name = name;
    this.maxEntities = maxEntities;
    this.minEntities = minEntities;
    this.cooldown = cooldown;
  }
}
